     }
 }
 ```

 **Indivisible long ops** тАФ `Task.WhenAny` + `Task.Delay` for progress:

 ```csharp
 private async Task RunLongQuery()
 {
     var queryTask = DatabaseService.RunExpensiveQueryAsync();
     while (queryTask != await Task.WhenAny(queryTask, Task.Delay(1000)))
     {
         status = "Still working...";
         StateHasChanged();
     }
     result = await queryTask;
 }
 ```

 ### Instead of `.Result` / `.Wait()` тАФ use `await`

 ```csharp
 // Wrong тАФ blocks the sync context, deadlocks the circuit
 private void Load()
 {
     var data = Http.GetFromJsonAsync<List<Item>>("api/items").Result;
 }

 // Correct тАФ use async all the way through
