 private readonly ConcurrentDictionary<string, int> cache = new();

 // Correct тАФ the sync context already prevents concurrent access
 private readonly Dictionary<string, int> cache = [];
 ```

 ### Instead of `Task.ContinueWith` тАФ use `await` with code after it

 ```csharp
 // Wrong тАФ continuation may run on a thread-pool thread
 private void Start()
 {
     _ = Http.GetFromJsonAsync<List<Item>>("api/items")
         .ContinueWith(t =>
         {
             items = t.Result;
             StateHasChanged(); // InvalidOperationException!
         });
 }

 // Correct тАФ straightforward async/await
 private async Task Start()
 {
     items = await Http.GetFromJsonAsync<List<Item>>("api/items");
 }
 ```

 ## Cancelling async work with CancellationToken

 Components that start long-running async operations (HTTP calls, database queries, streaming) should cancel that work when the component is disposed тАФ typically when the user navigates away.

 Use a `CancellationTokenSource` that is cancelled in `DisposeAsync`:

 ```razor
 @implements IAsyncDisposable
 @inject HttpClient Http

 <p>@status</p>

 @code {
     private string status = "Loading...";
     private CancellationTokenSource cts = new();

     protected override async Task OnInitializedAsync()
     {
         try
         {
             var data = await Http.GetFromJsonAsync<List<Item>>(
                 "api/items", cts.Token);
             status = $"Loaded {data?.Count} items.";
         }
         catch (OperationCanceledException)
         {
             // Component was disposed while loading тАФ expected, nothing to do.
         }
     }

     public ValueTask DisposeAsync()
     {
         cts.Cancel();
         cts.Dispose();
         return ValueTask.CompletedTask;
     }
 }
 ```

