@implements IAsyncDisposable
@inject IAddressValidator AddressValidator

<fieldset disabled="@isValidating">
    <label>
        Name
        <input @bind="name" />
    </label>
    <label>
        Address
        <input @bind="address" />
    </label>
    <label>
        City
        <input @bind="city" />
    </label>
    <label>
        Zip Code
        <input @bind="zipCode" />
    </label>
</fieldset>

@if (validationError is not null)
{
    <p class="validation-error">@validationError</p>
}

<button disabled="@isValidating" @onclick="HandleNext">
    @if (isValidating)
    {
        <span>ValidatingтАж</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    [Parameter, EditorRequired] public ShippingInfo Shipping { get; set; } = default!;
    [Parameter] public EventCallback<ShippingInfo> OnNext { get; set; }

    private string name = "";
    private string address = "";
    private string city = "";
    private string zipCode = "";
    private bool isValidating;
    private string? validationError;
    private CancellationTokenSource? cts;

    protected override void OnParametersSet()
    {
        name = Shipping.Name;
        address = Shipping.Address;
        city = Shipping.City;
        zipCode = Shipping.ZipCode;
    }

    private async Task HandleNext()
    {
        validationError = null;

        // Cancel any in-flight validation
        cts?.Cancel();
        cts?.Dispose();
        cts = new CancellationTokenSource();
        var token = cts.Token;

        isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                address, city, zipCode, token);

            if (!isValid)
            {
                validationError = "The address could not be validated.";
                return;
            }

            var result = new ShippingInfo
            {
                Name = name,
                Address = address,
                City = city,
                ZipCode = zipCode
            };
            await OnNext.InvokeAsync(result);
        }
        catch (OperationCanceledException)
        {
            // Previous validation was superseded or component disposed тАФ nothing to do.
        }
        finally
        {
            isValidating = false;
        }
    }

    public ValueTask DisposeAsync()
    {
        cts?.Cancel();
        cts?.Dispose();
        return ValueTask.CompletedTask;
    }
}

